python -c "
from outlines import prompt, register_filter, unregister_filter

register_filter('shout', lambda x: x.upper() + '!')

@prompt
def greet(text):
    '{{ text | shout }}'

print(greet('hello'))

unregister_filter('shout')

@prompt
def greet2(text):
    '{{ text | shout }}'

try:
    greet2('hello')
    print('ERROR: should have raised')
except Exception as e:
    print('OK, raised:', type(e).__name__)
"
